
import Vue from "vue";
import { Component, Prop } from "vue-property-decorator";
import { RequestDetails } from "@/types/notifications";
import { sprintf, __ } from "@/lib/i18n";

@Component({
  components: {}
})
export default class EmailForHost extends Vue {
  @Prop()
  requestDetails!: RequestDetails;

  get emailForHostText() {
    return this.getSupportTicketEmailText(
      this.requestDetails.responseCode,
      this.requestDetails.requestTimeGmt,
      this.requestDetails.requestUrl,
      this.requestDetails.requestMethod
    );
  }

  copyEmailForHostTextToClipboard() {
    const textArea = this.$refs.emailForHostTextarea;
    // @ts-ignore
    textArea.focus();
    // @ts-ignore
    textArea.select();
    document.execCommand("copy");
  }

  getSupportTicketEmailText(
    errorCode: string,
    requestTimeGmt: string,
    requestUri: string,
    requestType: string
  ) {
    return `${__("Hi Hosting Provider Support,")}

${__(
  "When using the Breakdance or Oxygen plugin, my server failed to fulfill the following request as expected. Instead, it returned an error code."
)}

${sprintf(__("Error Code: %s"), errorCode)}
${sprintf(__("Request Time: %s"), requestTimeGmt)}
${sprintf(__("Request URI: %s"), requestUri)}
${sprintf(__("Request Type: %s"), requestType)}

${sprintf(__("Why did the server return a %s error?"), errorCode)}

${__(
  "If this isn't something you can fix, please send me the full text of the error from the relevant error log file."
)}

${__("Best Regards,")}
${__("Your Name")}`;
  }
}
