
import Vue from "vue";
import { Component, Prop } from "vue-property-decorator";
import * as n from "@/types/notifications";
import EmailForHost from "@/components/Notifications/Types/Util/EmailForHost.vue";
import lodash from "lodash";
import { sprintf, _doc } from "@/lib/i18n";

@Component({
  components: {
    EmailForHost
  }
})
export default class FriendlyMultiError extends Vue {
  @Prop()
  value!: n.InternalServerErrorNotification | n.ForbiddenErrorNotification;

  get consultText500() {
    const url = this.$bdox("docs_link_troubleshooting_500");
    return sprintf(
      lodash.escape(
        _doc(
          'Consult our %stroubleshooting guide for the "500" error code%s',
          "1: Troubleshooting guide start tag, 2: Closing tag"
        )
      ),
      `<a href="${url}" target="_blank">`,
      "</a>"
    );
  }

  get consultText() {
    const url = this.$bdox("docs_link_troubleshooting_403");
    return sprintf(
      lodash.escape(
        _doc(
          'Consult our %stroubleshooting guide for the "403" error code%s which contains information your host can use to whitelist all requests coming from %s.',
          "1: Troubleshooting guide start tag, 2: Closing tag, 3: Plugin name"
        )
      ),
      `<a href="${url}" target="_blank">`,
      "</a>",
      this.$bdox("plugin_name")
    );
  }
}
