const { __, _x, _nx, sprintf } = window.wp.i18n;

// We want to use the i18n functions inside templates easily
export const i18nMixin = {
  methods: {
    __(text: string) {
      return __(text, "breakdance");
    },
    _x(text: string, context: string) {
      return _x(text, context, "breakdance");
    },
    _nx(single: string, plural: string, number: number, context: string) {
      return _nx(single, plural, number, context, "breakdance");
    },
    _doc(text: string, _explanation: string) {
      return __(text, "breakdance");
    },
    _xdoc(text: string, context: string, _explanation: string) {
      return _x(text, context, "breakdance");
    },
    sprintf
  }
};
