
import Vue from "vue";
import { Component, Prop } from "vue-property-decorator";
import * as n from "@/types/notifications";
import { configStore } from "@/store/store-accessor";
import TroubleshootingModal from "./TroubleshootingModal.vue";
import CopyButton from "@/components/Reusable/CopyButton.vue";
import { jsonStringifyOrUndefined } from "@/util/json-stringify-or-undefined";
import { sprintf, _doc, __ } from "@/lib/i18n";

@Component({
  components: {
    CopyButton,
    TroubleshootingModal
  }
})
export default class AjaxCodeError extends Vue {
  @Prop()
  value!: n.AjaxCodeErrorNotification;

  moreInfoDialogOpen = false;

  get notificationHeading() {
    const v = this.value;
    return sprintf(
      _doc("%s - Error Code %s", "1: friendly error name, 2: error code"),
      v.requestDetails?.friendlyName,
      v.requestDetails?.responseCode
    );
  }

  get ajaxErrorNotificationMessage() {
    return (
      this.value.errorDetails?.message ??
      this.value.errorMessage ??
      __("The task failed due a problem on the server side.")
    );
  }

  get valueForClipboard(): string | undefined {
    return jsonStringifyOrUndefined(this.value);
  }

  get troubleShootingModalOptions() {
    return { title: __("AJAX Error") };
  }

  get loginURL() {
    return configStore.neededData?.adminLoginUrl;
  }

  get isResponseCodeUnauthorized() {
    return this.value.requestDetails?.responseCode === "401";
  }

  setMoreInfoDialogOpen(open: boolean) {
    this.moreInfoDialogOpen = open;
  }
}
