
import Vue from "vue";
import { Component, Prop } from "vue-property-decorator";
import { __ } from "@/lib/i18n";

@Component({
  components: {}
})
export default class ConfirmDialog extends Vue {
  @Prop()
  show!: boolean;

  @Prop({ default: "info" })
  type: "success" | "warning" | "error" | "info" | undefined;

  @Prop({ default: false })
  hasCancel!: boolean;

  @Prop({ default: __("Cancel") })
  cancelText!: string;

  @Prop()
  saveIsEnabled!: boolean;

  @Prop()
  saveIsInProgress!: boolean;

  @Prop({ default: true })
  hasDiscard!: boolean;

  @Prop()
  discardIsEnabled!: boolean;

  @Prop()
  discardIsInProgress!: boolean;

  @Prop({ default: __("Save") })
  actionText!: string;

  @Prop({ default: __("Discard") })
  discardText!: string;
}
